import{_ as l,o as e,c as i,a0 as o}from"./chunks/framework.CSGB4SNl.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"java/eight-legged essay/java-hot200-day10.md","filePath":"java/eight-legged essay/java-hot200-day10.md"}'),t={name:"java/eight-legged essay/java-hot200-day10.md"};function r(s,a,d,h,n,c){return e(),i("div",null,[...a[0]||(a[0]=[o('<h4 id="什么是java内存模型jmm" tabindex="-1">什么是java内存模型JMM <a class="header-anchor" href="#什么是java内存模型jmm" aria-label="Permalink to &quot;什么是java内存模型JMM&quot;">​</a></h4><ol><li>jvm定义的一套规范，多线程变量如何在内存中存储和传递</li><li>JMM保证多线程环境下的可见性、有序性、原子性</li><li>还定义了一套约定，共享变量放在主内存中，每个线程都可以访问，但是每个线程都有自己的工作内存，存放共享内存的副本，且不能够直接去修改主存，变量间传递必须通过主内存</li></ol><h4 id="物理地址和逻辑地址" tabindex="-1">物理地址和逻辑地址 <a class="header-anchor" href="#物理地址和逻辑地址" aria-label="Permalink to &quot;物理地址和逻辑地址&quot;">​</a></h4><ol><li>物理地址是存储在硬件层面的，真正存储在内存条上的位置，逻辑地址是程序运行时的地址，操作系统将其指向逻辑地址</li></ol><h4 id="什么是api网关他有什么作用" tabindex="-1">什么是api网关他有什么作用 <a class="header-anchor" href="#什么是api网关他有什么作用" aria-label="Permalink to &quot;什么是api网关他有什么作用&quot;">​</a></h4><ol><li>主要是做微服务架构中的统一入口，不光是个路由器还能做，统一权限校验、熔断限流、日志监控、协议转化等</li><li>简化客户端调用，客户端无需知道后端拆分了多少个服务，统一鉴权，每个服务不用单独写权限校验等，直接在网关层面复用，熔断限流方便，直接在网关层面做拦截，确保过多请求不会直接打到服务</li></ol><h4 id="select、poll、epoll有什么区别" tabindex="-1">Select、Poll、Epoll有什么区别 <a class="header-anchor" href="#select、poll、epoll有什么区别" aria-label="Permalink to &quot;Select、Poll、Epoll有什么区别&quot;">​</a></h4><ol><li>都是操作系统中io多路复用相关的，让一个线程能够监听多个连接</li><li>Select相当于每个连接都问过去-固定连接数、Poll相当于有个长名单去询问-动态数组、Epoll就是连接主动通知线程-基于事件通知、红黑树 + 就绪链表</li></ol><h4 id="编译执行和解释执行的区别-jvm用哪种" tabindex="-1">编译执行和解释执行的区别，jvm用哪种 <a class="header-anchor" href="#编译执行和解释执行的区别-jvm用哪种" aria-label="Permalink to &quot;编译执行和解释执行的区别，jvm用哪种&quot;">​</a></h4><ol><li>编译执行是直接所有编译成机器码，然后跑机器码就可以了，但是跨平台能力不强，每个平台都要专门编译</li><li>解释执行是读一行翻译一行，虽然跨平台能力强了，但是执行效率低下</li><li>jvm是两者都有，先逐行编译，然后读取到热代码片段就作为本地机器码缓存起来</li></ol><h4 id="redis支持事务吗-如何实现" tabindex="-1">Redis支持事务吗，如何实现 <a class="header-anchor" href="#redis支持事务吗-如何实现" aria-label="Permalink to &quot;Redis支持事务吗，如何实现&quot;">​</a></h4><ol><li>支持，但是redis的事务和mysql不同，只能保证事务执行时不被其它事务插队，没法回滚，为啥不支持回滚，因为redis错误一般是语法错误或者对错误类型的key进行操作，回滚没意义，但是数据同步时没法回滚的话，那么就只能去清redis了</li><li>有四个命令，事务开启时进入一个队列，然后可以往队列里面插入多条命令，redis会回复是否就绪之类的</li><li>在正式开始排队执行事务前会先watch每个事务的key，如果有一个key被改了就整条队列作废</li><li>之后开始事务执行，此时其它事务、命令就无法干扰这个队列的执行，中途不想执行也可以把整个队列作废</li><li>redis因为是单线程的所有命令都打包一起执行，隔离性是最高的，也就不存在脏读、幻读、可重复读之类的</li></ol>',12)])])}const _=l(t,[["render",r]]);export{p as __pageData,_ as default};
